async function captureVisiblePage() {
  const width = Math.max(document.documentElement.scrollWidth, document.body.scrollWidth, window.innerWidth)
  const height = Math.max(document.documentElement.scrollHeight, document.body.scrollHeight, window.innerHeight)

  const canvas = document.createElement("canvas")
  canvas.width = width
  canvas.height = height
  const ctx = canvas.getContext("2d")
  ctx.fillStyle = "#fff"
  ctx.fillRect(0, 0, width, height)

  const svg = `
    <svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}">
      <foreignObject width="100%" height="100%">
        <div xmlns="http://www.w3.org/1999/xhtml" style="width:${width}px;height:${height}px;overflow:hidden;">
          ${document.documentElement.outerHTML}
        </div>
      </foreignObject>
    </svg>`
  const img = new Image()
  const url = URL.createObjectURL(new Blob([svg], { type: "image/svg+xml;charset=utf-8" }))
  await new Promise((resolve, reject) => {
    img.onload = resolve
    img.onerror = reject
    img.src = url
  })

  ctx.drawImage(img, 0, 0)
  URL.revokeObjectURL(url)

  const blob = await new Promise(resolve => canvas.toBlob(resolve, "image/png"))
  const a = document.createElement("a")
  a.href = URL.createObjectURL(blob)
  a.download = `screenshot-${Date.now()}.png`
  a.click()
  return "screenshot downloaded"
}

return await captureVisiblePage()

