Taking a canvas-based screenshot and downloading it now...


_____javascript
const canvas = document.createElement('canvas')
const w = document.documentElement.scrollWidth
const h = document.documentElement.scrollHeight
canvas.width = w
canvas.height = h
const ctx = canvas.getContext('2d')
ctx.fillStyle = '#fff'
ctx.fillRect(0, 0, w, h)

// Capture visible content only via a simple canvas raster of the current viewport
const vw = window.innerWidth
const vh = window.innerHeight
const svg = new XMLSerializer().serializeToString(document.documentElement)
const img = new Image()
const svgBlob = new Blob([svg], { type: 'image/svg+xml;charset=utf-8' })
const url = URL.createObjectURL(svgBlob)

await new Promise((resolve, reject) => {
  img.onload = () => {
    try {
      ctx.drawImage(img, 0, 0, vw, vh, 0, 0, vw, vh)
      resolve()
    } catch (e) {
      reject(e)
    }
  }
  img.onerror = reject
  img.src = url
})

URL.revokeObjectURL(url)

const a = document.createElement('a')
a.href = canvas.toDataURL('image/png')
a.download = `screenshot-${Date.now()}.png`
a.click()

return 'downloaded canvas screenshot'

