const widget = await space.current.readWidget("snake-game")
const original = widget.renderer

return await space.current.renderWidget({
  ...widget,
  renderer: async (parent, ...args) => {
    parent.innerHTML = `
      <style>
        .snake-wrap {
          position: relative;
          width: 100%;
          height: 100%;
          overflow: hidden;
          background: #111;
        }
        .snake-cell {
          position: absolute;
          width: 16px;
          height: 16px;
          border-radius: 4px;
          background: #7CFC00;
          box-shadow: 0 0 8px rgba(124,252,0,.35);
          transform: translate3d(0,0,0);
          transition: transform 110ms linear;
          will-change: transform;
        }
      </style>
      <div class="snake-wrap"></div>
    `
    const wrap = parent.querySelector(".snake-wrap")

    const cells = []
    const grid = 20
    const size = 16
    const gap = 2
    const step = size + gap

    let snake = [{ x: 8, y: 8 }]
    let dir = { x: 1, y: 0 }

    function ensureCells(n) {
      while (cells.length < n) {
        const el = document.createElement("div")
        el.className = "snake-cell"
        wrap.appendChild(el)
        cells.push(el)
      }
      while (cells.length > n) {
        cells.pop().remove()
      }
    }

    function draw() {
      ensureCells(snake.length)
      snake.forEach((seg, i) => {
        const el = cells[i]
        el.style.opacity = String(1 - i * 0.05)
        el.style.transform = `translate3d(${seg.x * step}px, ${seg.y * step}px, 0)`
      })
    }

    function tick() {
      const head = snake[0]
      const next = { x: head.x + dir.x, y: head.y + dir.y }
      if (next.x < 0) next.x = grid - 1
      if (next.y < 0) next.y = grid - 1
      if (next.x >= grid) next.x = 0
      if (next.y >= grid) next.y = 0
      snake = [next, ...snake.slice(0, -1)]
      draw()
    }

    draw()
    setInterval(tick, 120)

    if (typeof original === "function") {
      try { await original(parent, ...args) } catch {}
    }
  }
})

